import{C as a}from"./chunks/theme.Bv0bhO78.js";import{o as e,c as o,j as d,a as r,E as s,w as l,ae as i}from"./chunks/framework.PV3mkH3Y.js";const c=JSON.parse('{"title":"ประวัติการทำรายการ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/logs.md","filePath":"guide/logs.md"}'),n={name:"guide/logs.md"},m=Object.assign(n,{setup(h){return(b,t)=>(e(),o("div",null,[t[1]||(t[1]=d("h1",{id:"ประวัติการทํารายการ",tabindex:"-1"},[r("ประวัติการทำรายการ "),d("a",{class:"header-anchor",href:"#ประวัติการทํารายการ","aria-label":'Permalink to "ประวัติการทำรายการ"'},"​")],-1)),s(a,{title:"หน้าประวัติคืออะไร?",variant:"blue"},{default:l(()=>[...t[0]||(t[0]=[r(" หน้าประวัติแสดงการเคลื่อนไหวของวัสดุทั้งหมด — วัสดุเข้า, เบิกออก, ย้าย, เคลม, ตัด — ช่วยให้ตรวจสอบได้ว่าวัสดุแต่ละชิ้นไปอยู่ที่ไหนบ้าง ",-1)])]),_:1}),t[2]||(t[2]=i('<h2 id="ข้อมูลที่แสดง" tabindex="-1">ข้อมูลที่แสดง <a class="header-anchor" href="#ข้อมูลที่แสดง" aria-label="Permalink to &quot;ข้อมูลที่แสดง&quot;">​</a></h2><p>แต่ละรายการในประวัติแสดง:</p><table tabindex="0"><thead><tr><th>ข้อมูล</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>วัสดุ</td><td>ชื่อ ประเภท ความหนา สี ของวัสดุนั้น</td></tr><tr><td>ประเภทการทำรายการ</td><td>ดูหัวข้อถัดไป</td></tr><tr><td>จำนวน</td><td>บวก = เพิ่มสต็อก, ลบ = ลดสต็อก</td></tr><tr><td>ตำแหน่ง</td><td>ที่อยู่ในคลัง (ถ้ามี)</td></tr><tr><td>ออเดอร์ที่เกี่ยวข้อง</td><td>รหัสออเดอร์</td></tr><tr><td>ชิ้นงานที่เกี่ยวข้อง</td><td>หมายเลขชิ้นงาน (Pane)</td></tr><tr><td>พนักงาน</td><td>ชื่อผู้ทำรายการ</td></tr><tr><td>วันที่/เวลา</td><td>เวลาที่เกิดรายการ</td></tr></tbody></table><h2 id="ประเภทการทํารายการ" tabindex="-1">ประเภทการทำรายการ <a class="header-anchor" href="#ประเภทการทํารายการ" aria-label="Permalink to &quot;ประเภทการทำรายการ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ประเภท</th><th>ความหมาย</th></tr></thead><tbody><tr><td><strong>นำเข้า</strong></td><td>รับวัสดุเข้าคลัง เช่น รับกระจกใหม่จากซัพพลายเออร์</td></tr><tr><td><strong>ย้ายนำเข้า</strong></td><td>ย้ายวัสดุระหว่างตำแหน่งในคลัง (ฝั่งปลายทาง)</td></tr><tr><td><strong>เบิกออก</strong></td><td>เบิกวัสดุออกเพื่อใช้ในออเดอร์</td></tr><tr><td><strong>ย้ายออก</strong></td><td>ย้ายวัสดุออกจากตำแหน่ง (ฝั่งต้นทาง)</td></tr><tr><td><strong>เคลม</strong></td><td>วัสดุเสียหายหรือมีปัญหา</td></tr><tr><td><strong>ตัด</strong></td><td>วัสดุถูกนำไปตัด/ใช้ในการผลิต</td></tr></tbody></table><h2 id="การค้นหาและกรอง" tabindex="-1">การค้นหาและกรอง <a class="header-anchor" href="#การค้นหาและกรอง" aria-label="Permalink to &quot;การค้นหาและกรอง&quot;">​</a></h2><p>สามารถกรองรายการได้ตาม:</p><ul><li><strong>วัสดุ</strong> — ค้นหาชื่อวัสดุ</li><li><strong>ประเภทการทำรายการ</strong> — เลือกประเภทที่ต้องการดู</li><li><strong>ช่วงวันที่</strong> — กำหนดวันเริ่มต้นและสิ้นสุด</li><li><strong>พนักงาน</strong> — ดูรายการของพนักงานคนหนึ่ง</li></ul><h2 id="อัปเดตแบบเรียลไทม์" tabindex="-1">อัปเดตแบบเรียลไทม์ <a class="header-anchor" href="#อัปเดตแบบเรียลไทม์" aria-label="Permalink to &quot;อัปเดตแบบเรียลไทม์&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>รายการในหน้าประวัติอัปเดตอัตโนมัติเมื่อมีการทำรายการใหม่ — ไม่ต้องกดรีเฟรช</p></div><h2 id="ความสัมพันธ์กับส่วนอื่น" tabindex="-1">ความสัมพันธ์กับส่วนอื่น <a class="header-anchor" href="#ความสัมพันธ์กับส่วนอื่น" aria-label="Permalink to &quot;ความสัมพันธ์กับส่วนอื่น&quot;">​</a></h2><table tabindex="0"><thead><tr><th>การทำงาน</th><th>สร้างรายการประวัติประเภท</th></tr></thead><tbody><tr><td>นำเข้าวัสดุจากหน้าคลัง</td><td>นำเข้า</td></tr><tr><td>ย้ายวัสดุในคลัง</td><td>ย้ายนำเข้า + ย้ายออก</td></tr><tr><td>เบิกวัสดุจากสถานี</td><td>เบิกออก</td></tr><tr><td>แจ้งเคลมชิ้นงาน</td><td>เคลม</td></tr></tbody></table>',12))]))}});export{c as __pageData,m as default};
